class Store {
  constructor() {
    this.listeners = [];
    this.state = {};
  }

  subscribe(listener) {
    this.listeners.push(listener);
  }

  setState(next) {
    this.state = next;
    for (const listener of this.listeners) {
      listener(this.state);
    }
  }
}

function price(order, customer) {
  let total = order.items.reduce((sum, item) => sum + item.priceCents * item.quantity, 0);

  switch (customer.plan) {
    case 'standard':
      break;
    case 'pro':
      total *= 0.9;
      break;
    case 'enterprise':
      total *= 0.8;
      if (order.items.length > 100) total -= 5000;
      break;
    default:
      throw new Error('Unknown plan');
  }

  if (customer.country === 'US') total *= 1.07;
  if (customer.country === 'CA') total *= 1.13;

  return Math.round(total);
}
